  chat_vp_learned: { bg:'Запомних гласа ти 🙂 (мек сигнал — кодовата дума пак е ключът).', ru:'Запомнил твой голос 🙂 (мягкий сигнал — кодовое слово всё равно ключ).', uk:'Запам’ятав твій голос 🙂 (м’який сигнал — кодове слово все одно ключ).', en:'I remembered your voice 🙂 (soft signal — the code word is still the key).', de:'Ich habe deine Stimme gemerkt 🙂 (weiches Signal — das Codewort bleibt der Schlüssel).', fr:'J’ai mémorisé ta voix 🙂 (signal indicatif — le mot de passe reste la clé).', es:'Memoricé tu voz 🙂 (señal suave — la palabra clave sigue siendo la llave).', 'es-MX':'Memoricé tu voz 🙂 (señal suave — la palabra clave sigue siendo la llave).', it:'Ho memorizzato la tua voce 🙂 (segnale indicativo — la parola chiave resta la chiave).', pt:'Memorizei sua voz 🙂 (sinal suave — a palavra-chave continua sendo a chave).', ar:'حفظت صوتك 🙂 (إشارة تقريبية — كلمة السر تبقى المفتاح).', hi:'मैंने तुम्हारी आवाज़ याद रखी 🙂 (हल्का संकेत — कोड शब्द ही कुंजी है)।', ja:'あなたの声を覚えました 🙂（おおまかなサイン — 合言葉が鍵のままです）。', ky:'Үнүңдү эстеп калдым 🙂 (жумшак сигнал — сырсөз дагы эле ачкыч).', 'zh-Hant':'我記住了你的聲音 🙂（柔性訊號——密語仍是鑰匙）。' },
  chat_vp_recognized: { bg:'Познах те по гласа 🙂', ru:'Узнал тебя по голосу 🙂', uk:'Упізнав тебе за голосом 🙂', en:'I recognized you by your voice 🙂', de:'Ich habe dich an der Stimme erkannt 🙂', fr:'Je t’ai reconnu à ta voix 🙂', es:'Te reconocí por la voz 🙂', 'es-MX':'Te reconocí por la voz 🙂', it:'Ti ho riconosciuto dalla voce 🙂', pt:'Te reconheci pela voz 🙂', ar:'تعرّفت عليك من صوتك 🙂', hi:'मैंने तुम्हें आवाज़ से पहचाना 🙂', ja:'声であなただと分かりました 🙂', ky:'Үнүңдөн сени тааныдым 🙂', 'zh-Hant':'我聽聲音認出你了 🙂' },
