  chat_mic_title: { bg:'Говори', ru:'Говори', uk:'Говори', en:'Speak', de:'Sprich', fr:'Parle', es:'Habla', 'es-MX':'Habla', it:'Parla', pt:'Fale', ar:'تحدّث', hi:'बोलो', ja:'話す', ky:'Сүйлө', 'zh-Hant':'說話' },
  set_kb_mic: { bg:'Диктовка чрез клавиатурата', ru:'Диктовка через клавиатуру', uk:'Диктування через клавіатуру', en:'Dictate via keyboard', de:'Diktat über die Tastatur', fr:'Dictée via le clavier', es:'Dictado con el teclado', 'es-MX':'Dictado con el teclado', it:'Dettatura da tastiera', pt:'Ditado pelo teclado', ar:'الإملاء عبر لوحة المفاتيح', hi:'कीबोर्ड से डिक्टेशन', ja:'キーボードで音声入力', ky:'Клавиатура аркылуу диктовка', 'zh-Hant':'透過鍵盤聽寫' },
  set_kb_mic_desc: { bg:'🎤 бутонът отваря клавиатурата, за да диктуваш през нейния микрофон (най-точно). Изкл. → вграденият разпознавач.', ru:'Кнопка 🎤 открывает клавиатуру, чтобы диктовать её микрофоном (точнее всего). Выкл. → встроенный распознаватель.', uk:'Кнопка 🎤 відкриває клавіатуру, щоб диктувати її мікрофоном (найточніше). Вимк. → вбудований розпізнавач.', en:'The 🎤 button opens the keyboard so you dictate with its mic (most accurate). Off → built-in recognizer.', de:'Die 🎤-Taste öffnet die Tastatur, um mit ihrem Mikrofon zu diktieren (am genauesten). Aus → eingebauter Erkenner.', fr:'Le bouton 🎤 ouvre le clavier pour dicter avec son micro (le plus précis). Désactivé → reconnaissance intégrée.', es:'El botón 🎤 abre el teclado para dictar con su micrófono (lo más preciso). Apagado → reconocedor integrado.', 'es-MX':'El botón 🎤 abre el teclado para dictar con su micrófono (lo más preciso). Apagado → reconocedor integrado.', it:'Il pulsante 🎤 apre la tastiera per dettare col suo microfono (più preciso). Off → riconoscitore integrato.', pt:'O botão 🎤 abre o teclado para ditar com o microfone dele (mais preciso). Desligado → reconhecedor integrado.', ar:'زر 🎤 يفتح لوحة المفاتيح لتُملي عبر ميكروفونها (الأدق). إيقاف → المُتعرّف المدمج.', hi:'🎤 बटन कीबोर्ड खोलता है ताकि उसके माइक से बोलो (सबसे सटीक)। बंद → अंतर्निहित पहचानकर्ता।', ja:'🎤ボタンはキーボードを開き、そのマイクで入力します（最も正確）。オフ→内蔵認識。', ky:'🎤 баскычы клавиатураны ачат, анын микрофону менен айтасың (эң так). Өчүк → ички таануучу.', 'zh-Hant':'🎤 按鈕會開啟鍵盤，用它的麥克風聽寫（最準確）。關閉→內建辨識器。' },
  chat_kb_mic_hint: { bg:'Използвай микрофона на клавиатурата — той диктува най-точно (една сесия, без загуба на думи).', ru:'Используй микрофон клавиатуры — он диктует точнее всего (одна сессия, без потери слов).', uk:'Використовуй мікрофон клавіатури — він диктує найточніше (одна сесія, без втрати слів).', en:'Use the keyboard’s microphone — it dictates most accurately (one session, no lost words).', de:'Nutze das Mikrofon der Tastatur — es diktiert am genauesten (eine Sitzung, keine verlorenen Wörter).', fr:'Utilise le micro du clavier — il dicte le plus précisément (une seule session, sans perte de mots).', es:'Usa el micrófono del teclado — dicta con mayor precisión (una sesión, sin perder palabras).', 'es-MX':'Usa el micrófono del teclado — dicta con mayor precisión (una sola sesión, sin perder palabras).', it:'Usa il microfono della tastiera — detta con la massima precisione (una sessione, senza perdere parole).', pt:'Usa o microfone do teclado — dita com mais precisão (uma sessão, sem perder palavras).', ar:'استخدم ميكروفون لوحة المفاتيح — فهو يملي بأدق شكل (جلسة واحدة، بلا فقدان كلمات).', hi:'कीबोर्ड का माइक्रोफ़ोन इस्तेमाल करो — यह सबसे सटीक लिखता है (एक ही सत्र, शब्द नहीं छूटते)।', ja:'キーボードのマイクを使ってください — 最も正確に入力できます（1セッション、単語の欠落なし）。', ky:'Клавиатуранын микрофонун колдон — эң так жазат (бир сессия, сөздөр жоголбойт).', 'zh-Hant':'請使用鍵盤的麥克風——它聽寫最準確（單一工作階段，不漏字）。' },
  chat_conv_title: { bg:'Разговор (хендс-фрий глас)', ru:'Разговор (хендс-фри голос)', uk:'Розмова (хендс-фрі голос)', en:'Conversation (hands-free voice)', de:'Gespräch (Freisprech-Stimme)', fr:'Conversation (voix mains libres)', es:'Conversación (voz manos libres)', 'es-MX':'Conversación (voz manos libres)', it:'Conversazione (voce a mani libere)', pt:'Conversa (voz mãos-livres)', ar:'محادثة (صوت بدون استخدام اليدين)', hi:'बातचीत (हैंड्स-फ्री आवाज़)', ja:'会話（ハンズフリー音声）', ky:'Маек (колсуз үн)', 'zh-Hant':'對話（免持語音）' },
