  yt_video_id: { bg:'Видео id: {0} · {1}', ru:'Видео id: {0} · {1}', uk:'Відео id: {0} · {1}', en:'Video id: {0} · {1}', de:'Video-ID: {0} · {1}', fr:'Id vidéo : {0} · {1}', es:'Id de video: {0} · {1}', 'es-MX':'Id de video: {0} · {1}', it:'Id video: {0} · {1}', pt:'Id do vídeo: {0} · {1}', ar:'معرّف الفيديو: {0} · {1}', hi:'वीडियो id: {0} · {1}', ja:'動画 id: {0} · {1}', ky:'Видео id: {0} · {1}', 'zh-Hant':'影片 id：{0} · {1}' },
  yt_search_results: { bg:'Резултати от търсене (избери видео вътре, после копирай линка му за учене).', ru:'Результаты поиска (выбери видео внутри, затем скопируй его ссылку для обучения).', uk:'Результати пошуку (обери відео всередині, потім скопіюй його посилання для навчання).', en:'Search results (pick a video inside, then copy its link to learn).', de:'Suchergebnisse (wähle innen ein Video, kopiere dann seinen Link zum Lernen).', fr:'Résultats de recherche (choisis une vidéo dedans, puis copie son lien pour apprendre).', es:'Resultados de búsqueda (elige un video dentro, luego copia su enlace para aprender).', 'es-MX':'Resultados de búsqueda (elige un video dentro, luego copia su enlace para aprender).', it:'Risultati di ricerca (scegli un video dentro, poi copia il suo link per imparare).', pt:'Resultados da busca (escolha um vídeo dentro, depois copie o link dele para aprender).', ar:'نتائج البحث (اختر فيديو بالداخل، ثم انسخ رابطه للتعلّم).', hi:'खोज परिणाम (अंदर वीडियो चुनो, फिर सीखने के लिए उसका लिंक कॉपी करो)।', ja:'検索結果（中から動画を選び、学習用にそのリンクをコピー）。', ky:'Издөө натыйжалары (ичинен видео танда, анан үйрөнүү үчүн анын шилтемесин көчүр).', 'zh-Hant':'搜尋結果（在裡面選一部影片，再複製其連結來學習）。' },
