  set_per_call: { bg:'Искай одобрение при всяко повикване', ru:'Запрашивай одобрение при каждом вызове', uk:'Запитуй схвалення при кожному виклику', en:'Ask for approval on every call', de:'Bei jedem Aufruf um Genehmigung bitten', fr:'Demander l’approbation à chaque appel', es:'Pedir aprobación en cada llamada', 'es-MX':'Pedir aprobación en cada llamada', it:'Chiedi l’approvazione a ogni chiamata', pt:'Pedir aprovação em cada chamada', ar:'اطلب الموافقة عند كل استدعاء', hi:'हर कॉल पर अनुमोदन माँगें', ja:'呼び出しごとに承認を求める', ky:'Ар бир чакырууда жактыруу сура', 'zh-Hant':'每次呼叫都要求核准' },
  set_per_call_desc: { bg:'По-стриктно: одобрението важи само за едно повикване.', ru:'Строже: одобрение действует только для одного вызова.', uk:'Суворіше: схвалення діє лише для одного виклику.', en:'Stricter: approval applies to a single call only.', de:'Strenger: Die Genehmigung gilt nur für einen Aufruf.', fr:'Plus strict : l’approbation ne vaut que pour un seul appel.', es:'Más estricto: la aprobación se aplica a una sola llamada.', 'es-MX':'Más estricto: la aprobación se aplica a una sola llamada.', it:'Più rigoroso: l’approvazione vale solo per una chiamata.', pt:'Mais rigoroso: a aprovação vale só para uma chamada.', ar:'أكثر صرامة: تنطبق الموافقة على استدعاء واحد فقط.', hi:'अधिक सख़्त: अनुमोदन केवल एक कॉल पर लागू होता है।', ja:'より厳格: 承認は1回の呼び出しのみに適用されます。', ky:'Катуураак: жактыруу бир чакырууга гана колдонулат.', 'zh-Hant':'更嚴格：核准僅適用於單次呼叫。' },
