  sr_backup_btn: { bg:'Запази знанието', ru:'Сохранить знание', uk:'Зберегти знання', en:'Save the knowledge', de:'Wissen speichern', fr:'Sauvegarder le savoir', es:'Guardar el conocimiento', 'es-MX':'Guardar el conocimiento', it:'Salva la conoscenza', pt:'Salvar o conhecimento', ar:'احفظ المعرفة', hi:'ज्ञान सहेजें', ja:'知識を保存', ky:'Билимди сактоо', 'zh-Hant':'儲存知識' },
  sr_import_title: { bg:'Внеси от файл', ru:'Импорт из файла', uk:'Імпорт із файлу', en:'Import from file', de:'Aus Datei importieren', fr:'Importer depuis un fichier', es:'Importar desde archivo', 'es-MX':'Importar desde archivo', it:'Importa da file', pt:'Importar de arquivo', ar:'استيراد من ملف', hi:'फ़ाइल से आयात करें', ja:'ファイルから取り込み', ky:'Файлдан импорттоо', 'zh-Hant':'從檔案匯入' },
  sr_import_desc: { bg:'Зареди предишен бекъп (или пакет знание). Сливам в локалното, без дубликати — нищо не трия.', ru:'Загрузи предыдущий бэкап (или пакет знания). Я сливаю в локальное, без дубликатов — ничего не удаляю.', uk:'Завантаж попередню резервну копію (або пакет знання). Я зливаю в локальне, без дублікатів — нічого не видаляю.', en:'Load a previous backup (or a knowledge pack). I merge into the local one, without duplicates — I delete nothing.', de:'Lade ein früheres Backup (oder ein Wissenspaket). Ich füge es ins Lokale ein, ohne Duplikate — ich lösche nichts.', fr:'Charge une sauvegarde précédente (ou un pack de savoir). Je fusionne dans le local, sans doublons — je n’efface rien.', es:'Carga una copia previa (o un paquete de conocimiento). Lo fusiono en lo local, sin duplicados — no borro nada.', 'es-MX':'Carga un respaldo previo (o un paquete de conocimiento). Lo fusiono en lo local, sin duplicados — no borro nada.', it:'Carica un backup precedente (o un pacchetto di conoscenza). Lo unisco al locale, senza duplicati — non cancello nulla.', pt:'Carregue um backup anterior (ou um pacote de conhecimento). Eu mesclo no local, sem duplicatas — não apago nada.', ar:'حمّل نسخة احتياطية سابقة (أو حزمة معرفة). أدمجها في المحلي بلا تكرار — لا أحذف شيئًا.', hi:'पिछला बैकअप (या ज्ञान पैक) लोड करें। मैं इसे स्थानीय में मिलाता हूँ, बिना डुप्लिकेट — कुछ नहीं हटाता।', ja:'以前のバックアップ（または知識パック）を読み込みます。ローカルに重複なくマージし、何も削除しません。', ky:'Мурунку резервди (же билим топтомун) жүктө. Мен жергиликтүүгө кошом, кайталоосуз — эч нерсе өчүрбөйм.', 'zh-Hant':'載入先前的備份（或知識包）。我會併入本機，不產生重複——不刪除任何內容。' },
  sr_pick_file: { bg:'Първо избери файл.', ru:'Сначала выбери файл.', uk:'Спочатку вибери файл.', en:'First pick a file.', de:'Wähle zuerst eine Datei.', fr:'Choisis d’abord un fichier.', es:'Primero elige un archivo.', 'es-MX':'Primero elige un archivo.', it:'Prima scegli un file.', pt:'Primeiro escolha um arquivo.', ar:'اختر ملفًا أولًا.', hi:'पहले एक फ़ाइल चुनें।', ja:'まずファイルを選んでください。', ky:'Адегенде файл танда.', 'zh-Hant':'請先選擇檔案。' },
  sr_imported_new: { bg:'Внесох {0} нови (пропуснати {1}).', ru:'Я внёс {0} новых (пропущено {1}).', uk:'Я вніс {0} нових (пропущено {1}).', en:'Imported {0} new (skipped {1}).', de:'{0} neue importiert (übersprungen {1}).', fr:'{0} nouveaux importés (ignorés {1}).', es:'Importé {0} nuevos (omitidos {1}).', 'es-MX':'Importé {0} nuevos (omitidos {1}).', it:'Importati {0} nuovi (saltati {1}).', pt:'Importei {0} novos (ignorados {1}).', ar:'استوردت {0} جديدًا (تم تخطّي {1}).', hi:'{0} नए आयात किए (छोड़े गए {1})।', ja:'{0} 件を新規取り込み（スキップ {1} 件）。', ky:'{0} жаңы импорттодум (өткөрүлдү {1}).', 'zh-Hant':'已匯入 {0} 筆新資料（略過 {1} 筆）。' },
  sr_read_fail: { bg:'Не можах да прочета файла.', ru:'Не удалось прочитать файл.', uk:'Не вдалося прочитати файл.', en:'I could not read the file.', de:'Ich konnte die Datei nicht lesen.', fr:'Je n’ai pas pu lire le fichier.', es:'No pude leer el archivo.', 'es-MX':'No pude leer el archivo.', it:'Non sono riuscito a leggere il file.', pt:'Não consegui ler o arquivo.', ar:'تعذّر عليّ قراءة الملف.', hi:'मैं फ़ाइल नहीं पढ़ सका।', ja:'ファイルを読み取れませんでした。', ky:'Файлды окуй албадым.', 'zh-Hant':'我無法讀取該檔案。' },
