  sr_check_now: { bg:'Провери сега', ru:'Проверить сейчас', uk:'Перевірити зараз', en:'Check now', de:'Jetzt prüfen', fr:'Vérifier maintenant', es:'Comprobar ahora', 'es-MX':'Comprobar ahora', it:'Controlla ora', pt:'Verificar agora', ar:'تحقق الآن', hi:'अभी जाँचें', ja:'今すぐ確認', ky:'Азыр текшер', 'zh-Hant':'立即檢查' },
